// ExpenseForm.tsx
export function ExpenseForm({ onSubmit }) {
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState('food');
  const [description, setDescription] = useState('');
  const categories = ['food', 'transport', 'entertainment', 'shopping', 'bills', 'other'];
  return (
    <form onSubmit={() => onSubmit({ amount: parseFloat(amount), category, description, date: new Date() })}>
      <input type="number" value={amount} onChange={e => setAmount(e.target.value)} placeholder="Amount" />
      <select value={category} onChange={e => setCategory(e.target.value)}>
        {categories.map(c => <option key={c} value={c}>{c}</option>)}
      </select>
      <input value={description} onChange={e => setDescription(e.target.value)} placeholder="What was it for?" />
      <button type="submit">Add Expense</button>
    </form>
  );
}

// ExpenseList.tsx
export function ExpenseList({ expenses, onDelete }) {
  const total = expenses.reduce((sum, e) => sum + e.amount, 0);
  return (
    <div>
      <h2>Total: ₹{total.toFixed(2)}</h2>
      {expenses.map(e => (
        <div key={e.id}>
          <span>{e.category}</span>
          <span>₹{e.amount}</span>
          <span>{e.description}</span>
          <button onClick={() => onDelete(e.id)}>Delete</button>
        </div>
      ))}
    </div>
  );
}

// ExpensePieChart.tsx
export function ExpensePieChart({ expenses }) {
  const byCategory = expenses.reduce((acc, e) => { acc[e.category] = (acc[e.category] || 0) + e.amount; return acc; }, {});
  // renders pie chart using recharts
  return <PieChart data={Object.entries(byCategory).map(([name, value]) => ({ name, value }))} />;
}
